import{_ as t,o as i,c as a,ae as r}from"./chunks/framework.BGHOrOyn.js";const u=JSON.parse('{"title":"SingleFile","description":"https://github.com/gildas-lormeau/SingleFile","frontmatter":{"description":"https://github.com/gildas-lormeau/SingleFile"},"headers":[],"relativePath":"software-engineering/browsers/extensions/singlefile.md","filePath":"software-engineering/browsers/extensions/singlefile.md"}'),o={name:"software-engineering/browsers/extensions/singlefile.md"};function l(n,e,s,h,d,c){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="singlefile" tabindex="-1">SingleFile <a class="header-anchor" href="#singlefile" aria-label="Permalink to &quot;SingleFile&quot;">​</a></h1><h2 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&quot;">​</a></h2><p>SingleFile is a Web Extension (and a CLI tool) compatible with Chrome, Firefox (Desktop and Mobile), Microsoft Edge, Safari, Vivaldi, Brave, Waterfox, Yandex browser, and Opera. It helps you to save a complete web page into a single HTML file.</p><h3 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h3><ul><li>SingleFile <ul><li>Table of Contents</li><li>Demo</li><li>Install</li><li>Getting started</li><li>Additional notes</li><li>FAQ</li><li>Release notes</li><li>Known Issues</li><li>Troubleshooting unknown issues</li><li>Command Line Interface (SingleFile CLI)</li><li>Integration with user scripts</li><li>File format comparison</li><li>Projects using/compatible with SingleFile</li><li>Privacy Policy</li><li>Contributors</li><li>Code derived from third party projects</li><li>Icons</li><li>License</li></ul></li></ul><h3 id="demo" tabindex="-1">Demo <a class="header-anchor" href="#demo" aria-label="Permalink to &quot;Demo&quot;">​</a></h3><p><a href="https://user-images.githubusercontent.com/396787/156664907-cc458e35-f41b-45ca-91eb-372213812b44.mp4" target="_blank" rel="noreferrer">https://user-images.githubusercontent.com/396787/156664907-cc458e35-f41b-45ca-91eb-372213812b44.mp4</a></p><h3 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h3><p>SingleFile can be installed on:</p><ul><li>Firefox: <a href="https://addons.mozilla.org/firefox/addon/single-file" target="_blank" rel="noreferrer">https://addons.mozilla.org/firefox/addon/single-file</a></li><li>Firefox for Android: <a href="https://addons.mozilla.org/android/addon/single-file" target="_blank" rel="noreferrer">https://addons.mozilla.org/android/addon/single-file</a></li><li>Chrome: <a href="https://chrome.google.com/extensions/detail/mpiodijhokgodhhofbcjdecpffjipkle" target="_blank" rel="noreferrer">https://chrome.google.com/extensions/detail/mpiodijhokgodhhofbcjdecpffjipkle</a></li><li>Safari (macOS and iOS): <a href="https://apps.apple.com/us/app/singlefile-for-safari/id6444322545" target="_blank" rel="noreferrer">https://apps.apple.com/us/app/singlefile-for-safari/id6444322545</a></li><li>Microsoft Edge: <a href="https://microsoftedge.microsoft.com/addons/detail/efnbkdcfmcmnhlkaijjjmhjjgladedno" target="_blank" rel="noreferrer">https://microsoftedge.microsoft.com/addons/detail/efnbkdcfmcmnhlkaijjjmhjjgladedno</a></li></ul><p>You can also download the zip file (<a href="https://github.com/gildas-lormeau/SingleFile/archive/master.zip" target="_blank" rel="noreferrer">https://github.com/gildas-lormeau/SingleFile/archive/master.zip</a>) of the project and install it manually by unzipping it somewhere on your disk and following these instructions:</p><ul><li>Firefox: <a href="https://extensionworkshop.com/documentation/develop/temporary-installation-in-firefox/" target="_blank" rel="noreferrer">https://extensionworkshop.com/documentation/develop/temporary-installation-in-firefox/</a></li><li>Chrome: <a href="https://developer.chrome.com/docs/extensions/mv3/getstarted/development-basics/#load-unpacked" target="_blank" rel="noreferrer">https://developer.chrome.com/docs/extensions/mv3/getstarted/development-basics/#load-unpacked</a></li><li>Microsoft Edge: <a href="https://docs.microsoft.com/en-us/microsoft-edge/extensions-chromium/getting-started/extension-sideloading" target="_blank" rel="noreferrer">https://docs.microsoft.com/en-us/microsoft-edge/extensions-chromium/getting-started/extension-sideloading</a></li><li>Safari: <a href="https://github.com/gildas-lormeau/SingleFile-Safari-Extension" target="_blank" rel="noreferrer">https://github.com/gildas-lormeau/SingleFile-Safari-Extension</a></li></ul><h3 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started&quot;">​</a></h3><ul><li>Click on the SingleFile button in the extension toolbar to save the page.</li><li>You can click again on the button to cancel the action when processing a page.</li></ul><h3 id="additional-notes" tabindex="-1">Additional notes <a class="header-anchor" href="#additional-notes" aria-label="Permalink to &quot;Additional notes&quot;">​</a></h3><ul><li>Open the context menu by right-clicking the SingleFile button in the extension toolbar or on the webpage. It allows you to save: <ul><li>the current tab,</li><li>the selected content,</li><li>the selected frame.</li></ul></li><li>You can also process multiple tabs in one click and save: <ul><li>the selected tabs,</li><li>the unpinned tabs,</li><li>all the tabs.</li></ul></li><li>Select &quot;Annotate and save the page...&quot; in the context menu to: <ul><li>highlight text,</li><li>add notes,</li><li>remove content.</li></ul></li><li>The context menu also allows you to activate the auto-save of: <ul><li>the current tab,</li><li>the unpinned tabs,</li><li>all the tabs.</li></ul></li><li>With auto-save active, pages are automatically saved every time after being loaded (or before being unloaded if not).</li><li>Right-click on the SingleFile button and select &quot;Manage extension&quot; (Firefox) / &quot;Options&quot; (Chrome) to open the options page.</li><li>Enable the option &quot;Destination &gt; save to Google Drive&quot; or &quot;Destination &gt; upload to GitHub&quot; to upload pages to Google Drive or GitHub respectively.</li><li>Enable the option &quot;Misc. &gt; add proof of existence&quot; to prove the existence of saved pages by linking the SHA256 of the pages into the blockchain.</li><li>You can use the customizable shortkey Ctrl+Shift+Y to save the current tab or the selected tabs. Go to about:addons and select &quot;Manage extension shortcuts&quot; in the cogwheel menu to change it in Firefox. Go to chrome://extensions/shortcuts to change it in Chrome.</li><li>The default save folder is the download folder configured in your browser, cf. about:addons in Firefox and chrome://settings in Chrome.</li><li>See the extension help in the options page for more detailed information about the options and technical notes.</li></ul><h3 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h3><p>See <a href="https://github.com/gildas-lormeau/SingleFile/blob/master/faq.md" target="_blank" rel="noreferrer">https://github.com/gildas-lormeau/SingleFile/blob/master/faq.md</a></p><h3 id="release-notes" tabindex="-1">Release notes <a class="header-anchor" href="#release-notes" aria-label="Permalink to &quot;Release notes&quot;">​</a></h3><p>See <a href="https://addons.mozilla.org/firefox/addon/single-file/versions/" target="_blank" rel="noreferrer">https://addons.mozilla.org/firefox/addon/single-file/versions/</a></p><h3 id="known-issues" tabindex="-1">Known Issues <a class="header-anchor" href="#known-issues" aria-label="Permalink to &quot;Known Issues&quot;">​</a></h3><ul><li>All browsers: <ul><li>For security reasons, you cannot save pages hosted on <a href="https://chrome.google.com" target="_blank" rel="noreferrer">https://chrome.google.com</a>, <a href="https://addons.mozilla.org" target="_blank" rel="noreferrer">https://addons.mozilla.org</a> and some other Mozilla domains. When this happens, 🛇 is displayed on top of the SingleFile icon.</li><li>For <a href="https://developer.mozilla.org/en-US/docs/Web/HTML/CORS_enabled_image" target="_blank" rel="noreferrer">security reasons</a>, SingleFile is sometimes unable to save the image representation of <a href="https://developer.mozilla.org/docs/Web/HTML/Element/canvas" target="_blank" rel="noreferrer">canvas</a> and snapshots of <a href="https://developer.mozilla.org/docs/Web/HTML/Element/video" target="_blank" rel="noreferrer">video</a> elements.</li><li>The last saved path cannot be remembered by default. To circumvent this limitation, disable the option &quot;Misc &gt; save pages in background&quot;.</li><li>The following characters are replaced with <code>_</code> in file names: <code>~</code>, <code>+</code>, <code>\\</code>, <code>?</code>, <code>%</code>, <code>*</code>, <code>:</code>, <code>|</code>, <code>&quot;</code>, <code>&lt;</code>, <code>&gt;</code>. This is done to maintain compatibility with various OSs and file systems. If you don&#39;t need that level of compatibility and know what you are doing, you can change the list of forbidden characters in <a href="https://github.com/gildas-lormeau/SingleFile/wiki/Hidden-options" target="_blank" rel="noreferrer">Hidden options</a>.</li></ul></li><li>Chromium-based browsers: <ul><li>You must enable the option &quot;Allow access to file URLs&quot; in the extension page to display the infobar when viewing a saved page, and to save or to annotate a page stored on the filesystem.</li><li>If the file name of a saved page looks like &quot;56833935-156b-4d8c-a00f-19599c6513d3.html&quot;, disable the option &quot;Misc &gt; save pages in background&quot;. Reinstalling the browser may also fix this issue. You can find more info about this bug <a href="https://bugs.chromium.org/p/chromium/issues/detail?id=892133" target="_blank" rel="noreferrer">here</a>.</li><li>Disabling the option &quot;File name &gt; open the &quot;Save as&quot; dialog to confirm the file name&quot; will work if and only if the option &quot;Ask where to save each file before downloading&quot; is disabled in chrome://settings/downloads.</li></ul></li><li>Firefox: <ul><li>The &quot;File name &gt; file name conflict resolution&quot; option does not work if set to &quot;prompt for a name&quot;</li><li>Sometimes, SingleFile is unable to save the contents of sandboxed iframes because of <a href="https://bugzilla.mozilla.org/show_bug.cgi?id=1411641" target="_blank" rel="noreferrer">this bug</a>.</li><li>When processing a page from the filesystem, external resources (e.g. images, stylesheets, fonts etc.) will not be embedded into the saved page. You can find more info about this bug <a href="https://bugzilla.mozilla.org/show_bug.cgi?id=1644488" target="_blank" rel="noreferrer">here</a>. This bug has been closed by Mozilla as &quot;WontFix&quot;. But there is a simple workaround proposed <a href="https://github.com/gildas-lormeau/SingleFile/issues/7#issuecomment-618980153" target="_blank" rel="noreferrer">here</a>.</li></ul></li><li>Waterfox Classic <ul><li>User interface elements displayed in the page (progress bar, logs panel) won&#39;t be displayed unless <code>dom.webcomponents.enabled</code> is enabled in <code>about:config</code>.</li><li>When opening pages saved with the option &quot;Images &gt; group duplicate images together&quot; enabled, some duplicate images might not displayed. It is recommended to disable this option.</li></ul></li></ul><h3 id="troubleshooting-unknown-issues" tabindex="-1">Troubleshooting unknown issues <a class="header-anchor" href="#troubleshooting-unknown-issues" aria-label="Permalink to &quot;Troubleshooting unknown issues&quot;">​</a></h3><p>Please follow these steps if you find an unknown issue:</p><ul><li>Save the page in incognito.</li><li>If saving page in incognito did not fix the issue, reset SingleFile options.</li><li>If resetting options did not fix the issue, restart the browser.</li><li>If restarting the browser did not fix the issue, try to disable all other extensions to see if there is a conflict.</li><li>If there is a conflict then try to determine against which extension(s).</li><li>Please report the issue with a short description on how to reproduce it here: <a href="https://github.com/gildas-lormeau/SingleFile/issues" target="_blank" rel="noreferrer">https://github.com/gildas-lormeau/SingleFile/issues</a>.</li></ul><h3 id="command-line-interface-singlefile-cli" tabindex="-1">Command Line Interface (SingleFile CLI) <a class="header-anchor" href="#command-line-interface-singlefile-cli" aria-label="Permalink to &quot;Command Line Interface (SingleFile CLI)&quot;">​</a></h3><p>You can save web pages to HTML from the command line interface. See here for more info: <a href="https://github.com/gildas-lormeau/single-file-cli" target="_blank" rel="noreferrer">https://github.com/gildas-lormeau/single-file-cli</a>.</p><h3 id="integration-with-user-scripts" tabindex="-1">Integration with user scripts <a class="header-anchor" href="#integration-with-user-scripts" aria-label="Permalink to &quot;Integration with user scripts&quot;">​</a></h3><p>You can execute a user script just before (and after) SingleFile saves a page. For more info, see <a href="https://github.com/gildas-lormeau/SingleFile/wiki/How-to-execute-a-user-script-before-a-page-is-saved" target="_blank" rel="noreferrer">https://github.com/gildas-lormeau/SingleFile/wiki/How-to-execute-a-user-script-before-a-page-is-saved</a>.</p><h3 id="file-format-comparison" tabindex="-1">File format comparison <a class="header-anchor" href="#file-format-comparison" aria-label="Permalink to &quot;File format comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th style="text-align:center;">HTML</th><th style="text-align:center;">Self-extracting ZIP</th><th style="text-align:center;">MHTML</th><th style="text-align:center;">Webarchive (Safari)</th><th style="text-align:center;">HTML+folder</th></tr></thead><tbody><tr><td>Pages are saved as a single file</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;"></td></tr><tr><td>HTML and styles are minified</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Unused HTML and styles are removed from files</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Binary resources are not encoded in base 64</td><td style="text-align:center;"></td><td style="text-align:center;">✓</td><td style="text-align:center;"></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr><tr><td>Files are compressed</td><td style="text-align:center;"></td><td style="text-align:center;">✓</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Files can be viewed without installing any extension</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓¹</td><td style="text-align:center;">✓²</td><td style="text-align:center;">✓³</td><td style="text-align:center;">✓</td></tr><tr><td>Files can be viewed without running JavaScript</td><td style="text-align:center;">✓</td><td style="text-align:center;"></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr><tr><td>Files can be unzipped to extract page resources</td><td style="text-align:center;"></td><td style="text-align:center;">✓</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">n/a</td></tr><tr><td>Files contains the text of the page (plain or formatted) which can be indexed</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓⁴</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr></tbody></table><p>Footnotes:</p><p>¹ When using the &quot;universal&quot; self-extracting file format.</p><p>² Only in Chromium-based browsers, and Internet Explorer.</p><p>³ Only in Safari.</p><p>⁴ An option must be enabled in the extension.</p><h3 id="projects-using-compatible-with-singlefile" tabindex="-1">Projects using/compatible with SingleFile <a class="header-anchor" href="#projects-using-compatible-with-singlefile" aria-label="Permalink to &quot;Projects using/compatible with SingleFile&quot;">​</a></h3><ul><li>ArchiveBox - Open-source self-hosted web archiving: <a href="https://github.com/ArchiveBox/ArchiveBox" target="_blank" rel="noreferrer">https://github.com/ArchiveBox/ArchiveBox</a></li><li>htmls-to-datasette - Tool to index HTML files into a Sqlite database: <a href="https://github.com/pjamar/htmls-to-datasette" target="_blank" rel="noreferrer">https://github.com/pjamar/htmls-to-datasette</a></li><li>obsidian-html-plugin - Plugin for reading HTML pages in Obsidian: <a href="https://github.com/nuthrash/obsidian-html-plugin" target="_blank" rel="noreferrer">https://github.com/nuthrash/obsidian-html-plugin</a></li><li>Petal Cite Web Importer - Browser extension to save PDFs and capture web pages in Petal Cite: <a href="https://github.com/ks-collab/cite-extension" target="_blank" rel="noreferrer">https://github.com/ks-collab/cite-extension</a></li><li>singlefile2trilium - Tool to save faithful copy of a web page as a Trilium note with SingleFile: <a href="https://github.com/nil0x42/singlefile2trilium" target="_blank" rel="noreferrer">https://github.com/nil0x42/singlefile2trilium</a></li><li>SingleFileMac - Integration of SingleFile in a swift application using webkit: <a href="https://github.com/david-littlefield/SingleFileMac" target="_blank" rel="noreferrer">https://github.com/david-littlefield/SingleFileMac</a></li><li>Trilium-SingleFile - An addon for Trilium Notes to easily import SingleFile html pages: <a href="https://github.com/rauenzi/Trilium-SingleFile" target="_blank" rel="noreferrer">https://github.com/rauenzi/Trilium-SingleFile</a></li><li>Trilium Simple SingleFile Renderer - A plugin to add a new Template note to Trilium for render file created by SingleFile: <a href="https://github.com/xnohat/trilium-simple-singlefile-renderer" target="_blank" rel="noreferrer">https://github.com/xnohat/trilium-simple-singlefile-renderer</a></li><li>Zotero Connector - Browser extension for Zotero, a tool to help you collect, organize, cite, and share your research sources: <a href="https://github.com/zotero/zotero-connectors" target="_blank" rel="noreferrer">https://github.com/zotero/zotero-connectors</a></li></ul><h3 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h3><p>See <a href="https://github.com/gildas-lormeau/SingleFile/blob/master/privacy.md" target="_blank" rel="noreferrer">https://github.com/gildas-lormeau/SingleFile/blob/master/privacy.md</a></p><h3 id="contributors" tabindex="-1">Contributors <a class="header-anchor" href="#contributors" aria-label="Permalink to &quot;Contributors&quot;">​</a></h3><ul><li>Chinese translation done by yfdyh000 (<a href="https://github.com/yfdyh000" target="_blank" rel="noreferrer">https://github.com/yfdyh000</a>), KrasnayaPloshchad (<a href="https://github.com/KrasnayaPloshchad" target="_blank" rel="noreferrer">https://github.com/KrasnayaPloshchad</a>), frostblazergit (<a href="https://github.com/frostblazergit" target="_blank" rel="noreferrer">https://github.com/frostblazergit</a>), dnknn (<a href="https://github.com/dnknn" target="_blank" rel="noreferrer">https://github.com/dnknn</a>), lqzhgood (<a href="https://github.com/lqzhgood" target="_blank" rel="noreferrer">https://github.com/lqzhgood</a>)</li><li>Traditional Chinese translation done by frostblazergit (<a href="https://github.com/frostblazergit" target="_blank" rel="noreferrer">https://github.com/frostblazergit</a>), lqzhgood (<a href="https://github.com/lqzhgood" target="_blank" rel="noreferrer">https://github.com/lqzhgood</a>)</li><li>German translation done by womotroll (<a href="https://github.com/womotroll" target="_blank" rel="noreferrer">https://github.com/womotroll</a>), bannmann (<a href="https://github.com/bannmann" target="_blank" rel="noreferrer">https://github.com/bannmann</a>)</li><li>Italian translation done by Fastbyte01 (<a href="https://github.com/Fastbyte01" target="_blank" rel="noreferrer">https://github.com/Fastbyte01</a>)</li><li>Japanese translation done by Shitennouji（四天王寺) (<a href="https://github.com/Shitennouji" target="_blank" rel="noreferrer">https://github.com/Shitennouji</a>)</li><li>Polish translation done by xesarni (<a href="https://github.com/xesarni" target="_blank" rel="noreferrer">https://github.com/xesarni</a>)</li><li>Portuguese translation done by Blackspirits (<a href="https://github.com/Blackspirits" target="_blank" rel="noreferrer">https://github.com/Blackspirits</a>)</li><li>Portuguese-Brazilian translation done by @mezysinc, Blackspirits (<a href="https://github.com/Blackspirits" target="_blank" rel="noreferrer">https://github.com/Blackspirits</a>)</li><li>Russian translation done by rstp14, kramola-RU (<a href="https://github.com/kramola-RU" target="_blank" rel="noreferrer">https://github.com/kramola-RU</a>), solokot (<a href="https://github.com/solokot" target="_blank" rel="noreferrer">https://github.com/solokot</a>), TotalCaesar659 (<a href="https://github.com/TotalCaesar659" target="_blank" rel="noreferrer">https://github.com/TotalCaesar659</a>)</li><li>Spanish translation done by strel (<a href="https://github.com/strel" target="_blank" rel="noreferrer">https://github.com/strel</a>)</li><li>Turkish translation done by hbaklan943 (<a href="https://github.com/hbaklan943" target="_blank" rel="noreferrer">https://github.com/hbaklan943</a>)</li><li>Ukrainian translation done by perdolka (<a href="https://github.com/perdolka" target="_blank" rel="noreferrer">https://github.com/perdolka</a>), gildas-lormeau</li></ul><h3 id="code-derived-from-third-party-projects" tabindex="-1">Code derived from third party projects <a class="header-anchor" href="#code-derived-from-third-party-projects" aria-label="Permalink to &quot;Code derived from third party projects&quot;">​</a></h3><ul><li>csstree: <a href="https://github.com/csstree/csstree" target="_blank" rel="noreferrer">https://github.com/csstree/csstree</a></li><li>postcss-media-query-parser: <a href="https://github.com/dryoma/postcss-media-query-parser" target="_blank" rel="noreferrer">https://github.com/dryoma/postcss-media-query-parser</a></li><li>postcss-selector-parser: <a href="https://github.com/postcss/postcss-selector-parser" target="_blank" rel="noreferrer">https://github.com/postcss/postcss-selector-parser</a></li><li>UglifyCSS: <a href="https://github.com/fmarcia/UglifyCSS" target="_blank" rel="noreferrer">https://github.com/fmarcia/UglifyCSS</a></li><li>parse-srcset: <a href="https://github.com/albell/parse-srcset" target="_blank" rel="noreferrer">https://github.com/albell/parse-srcset</a></li><li>parse-css-font: <a href="https://github.com/jedmao/parse-css-font" target="_blank" rel="noreferrer">https://github.com/jedmao/parse-css-font</a></li><li>Readability: <a href="https://github.com/mozilla/readability" target="_blank" rel="noreferrer">https://github.com/mozilla/readability</a></li><li>whatwg-mimetype: <a href="https://github.com/jsdom/whatwg-mimetype" target="_blank" rel="noreferrer">https://github.com/jsdom/whatwg-mimetype</a></li></ul><h3 id="icons" tabindex="-1">Icons <a class="header-anchor" href="#icons" aria-label="Permalink to &quot;Icons&quot;">​</a></h3><ul><li>Icon made by <a href="https://www.flaticon.com/authors/kiranshastry" target="_blank" rel="noreferrer">Kiranshastry</a> from <a href="https://www.flaticon.com/" target="_blank" rel="noreferrer">Flaticon</a> is licensed by <a href="http://creativecommons.org/licenses/by/3.0/" target="_blank" rel="noreferrer">CC 3.0 BY</a></li></ul><h3 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h3><p>SingleFile is licensed under AGPL. Code derived from third-party projects is licensed under MIT. Please contact me at gildas.lormeau &lt;at&gt; gmail.com if you are interested in licensing the SingleFile code for a commercial service or product.</p><p>Suggestions are welcome 😃</p>',49)])])}const m=t(o,[["render",l]]);export{u as __pageData,m as default};
